class PairwiseJudgeModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.rlm = dspy.RLM(dspy.Signature('question: str, response_a: str, response_b: str -> winner: str', 'Decide which of two candidate responses better answers the user\'s question.\n\nYou are given a `question` and two responses, `response_a` and `response_b`. Return `winner` as\nexactly "A" or "B" — the response that is more helpful, relevant, correct, and appropriate.\n\nPrefer to encode the judging logic as a deterministic Python scoring function over the two\nresponses and choose the higher-scoring one; reserve an LLM call only for genuinely ambiguous\ncases. Judge on substance, not length or formatting.'))

    def forward(self, **inputs):
        result = self.rlm(**inputs)
        return dspy.Prediction(winner=result.winner)
